ps.pstext:
if !IsFeatureImplemented(FEAT_SME_F16F16) then EndOfDecode(Decode_UNDEF); end;
let v : integer = UInt('010'::Rv);
let esize : integer{} = 16;
let n : integer = UInt(Zn::'0');
let m : integer = UInt('0'::Zm);
let offset : integer = UInt(off3);
let index : integer = UInt(i3h::i3l);
let nreg : integer{} = 2;

if !IsFeatureImplemented(FEAT_SME2) then EndOfDecode(Decode_UNDEF); end;
let v : integer = UInt('010'::Rv);
let esize : integer{} = 32;
let n : integer = UInt(Zn::'0');
let m : integer = UInt('0'::Zm);
let offset : integer = UInt(off3);
let index : integer = UInt(i2);
let nreg : integer{} = 2;

if !(IsFeatureImplemented(FEAT_SME2) && IsFeatureImplemented(FEAT_SME_F64F64)) then
    EndOfDecode(Decode_UNDEF);
end;
let v : integer = UInt('010'::Rv);
let esize : integer{} = 64;
let n : integer = UInt(Zn::'0');
let m : integer = UInt('0'::Zm);
let offset : integer = UInt(off3);
let index : integer = UInt(i1);
let nreg : integer{} = 2;

if !IsFeatureImplemented(FEAT_SME_F16F16) then EndOfDecode(Decode_UNDEF); end;
let v : integer = UInt('010'::Rv);
let esize : integer{} = 16;
let n : integer = UInt(Zn::'00');
let m : integer = UInt('0'::Zm);
let offset : integer = UInt(off3);
let index : integer = UInt(i3h::i3l);
let nreg : integer{} = 4;

if !IsFeatureImplemented(FEAT_SME2) then EndOfDecode(Decode_UNDEF); end;
let v : integer = UInt('010'::Rv);
let esize : integer{} = 32;
let n : integer = UInt(Zn::'00');
let m : integer = UInt('0'::Zm);
let offset : integer = UInt(off3);
let index : integer = UInt(i2);
let nreg : integer{} = 4;

if !(IsFeatureImplemented(FEAT_SME2) && IsFeatureImplemented(FEAT_SME_F64F64)) then
    EndOfDecode(Decode_UNDEF);
end;
let v : integer = UInt('010'::Rv);
let esize : integer{} = 64;
let n : integer = UInt(Zn::'00');
let m : integer = UInt('0'::Zm);
let offset : integer = UInt(off3);
let index : integer = UInt(i1);
let nreg : integer{} = 4;

CheckStreamingSVEAndZAEnabled();
let VL : integer{} = CurrentVL();
let elements : integer = VL DIV esize;
let vectors : integer = VL DIV 8;
let vstride : integer = vectors DIV nreg;
let eltspersegment : integer = 128 DIV esize;
let vbase : bits(32) = X{}(v);
var vec : integer = (UInt(vbase) + offset) MOD vstride;
var result : bits(VL);

for r = 0 to nreg-1 do
    let op1 : bits(VL) = Z{}(n+r);
    let op2 : bits(VL) = Z{}(m);
    let op3 : bits(VL) = ZAvector{}(vec);
    for e = 0 to elements-1 do
        let elem1 : bits(esize) = FPNeg{}(op1[e*:esize], FPCR());
        let segmentbase : integer = e - (e MOD eltspersegment);
        let s : integer = segmentbase + index;
        let elem2 : bits(esize) = op2[s*:esize];
        let elem3 : bits(esize) = op3[e*:esize];
        result[e*:esize] = FPMulAdd_ZA{esize}(elem3, elem1, elem2, FPCR());
    end;
    ZAvector{VL}(vec) = result;
    vec = vec + vstride;
end;
